import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Audiencia {
  id: number;
  dataAudiencia: string;
  horarioInicio: string;
  status: string;
  competencia: string;
  vara: {
    id: number;
    nome: string;
  };
  juiz: {
    id: number;
    nome: string;
  };
  promotor: {
    id: number;
    nome: string;
  };
  numeroProcesso: string;
  reuPreso: boolean;
  agendamentoTeams: boolean;
  reconhecimento: boolean;
  depoimentoEspecial: boolean;
}

const AudienciasList: React.FC = () => {
  const [audiencias, setAudiencias] = useState<Audiencia[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [filtroProcesso, setFiltroProcesso] = useState<string>('');
  const [dataFiltro, setDataFiltro] = useState<string>('');
  const [filtroCompetencia, setFiltroCompetencia] = useState<string>('');
  const [filtroReuPreso, setFiltroReuPreso] = useState<string>('');
  const [filtroAgendamentoTeams, setFiltroAgendamentoTeams] = useState<string>('');
  const [filtroReconhecimento, setFiltroReconhecimento] = useState<string>('');
  const [filtroDepoimentoEspecial, setFiltroDepoimentoEspecial] = useState<string>('');

  // Estados para paginação
  const [paginaAtual, setPaginaAtual] = useState<number>(1);
  const [itensPorPagina] = useState<number>(10);

  useEffect(() => {
    const fetchAudiencias = async () => {
      try {
        setLoading(true);
        let url = '/api/audiencias/por-competencia';
        if (filtroCompetencia) {
          url += `?competencia=${encodeURIComponent(filtroCompetencia)}`;
        }
        const response = await axios.get<Audiencia[]>(url);
        setAudiencias(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar audiências. Por favor, tente novamente.');
        console.error('Erro ao buscar audiências:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchAudiencias();
  }, [filtroCompetencia]);

  const handleDelete = async (id: number, processo: string) => {
    if (!window.confirm(`Tem certeza que deseja excluir a audiência do processo "${processo}"?`)) {
      return;
    }

    try {
      await axios.delete(`/api/audiencias/${id}`);
      setAudiencias(audiencias.filter(audiencia => audiencia.id !== id));
    } catch (err) {
      setError('Erro ao excluir audiência. Por favor, tente novamente.');
      console.error('Erro ao excluir audiência:', err);
    }
  };

  const formatarData = (data: string): string => {
    try {
      return format(new Date(data), 'dd/MM/yyyy', { locale: ptBR });
    } catch (error) {
      return data;
    }
  };

  const formatarHora = (hora: string): string => {
    try {
      return hora.substring(0, 5); // Pega apenas HH:MM
    } catch (error) {
      return hora || '';
    }
  };

  const audienciasFiltradas = audiencias.filter(audiencia => {
    const termoBusca = filtroProcesso.toLowerCase();
    const dataFormatada = formatarData(audiencia.dataAudiencia);

    const correspondeAoFiltro = 
      (audiencia.numeroProcesso || '').toLowerCase().includes(termoBusca) ||
      (audiencia.vara?.nome || '').toLowerCase().includes(termoBusca) ||
      (audiencia.juiz?.nome || '').toLowerCase().includes(termoBusca) ||
      (audiencia.promotor?.nome || '').toLowerCase().includes(termoBusca) ||
      (audiencia.status || '').toLowerCase().includes(termoBusca);

    const correspondeAData = dataFiltro ? dataFormatada === dataFiltro : true;

    const correspondeReuPreso = filtroReuPreso ? 
      (filtroReuPreso === 'sim' ? audiencia.reuPreso : !audiencia.reuPreso) : true;

    const correspondeAgendamentoTeams = filtroAgendamentoTeams ? 
      (filtroAgendamentoTeams === 'sim' ? audiencia.agendamentoTeams : !audiencia.agendamentoTeams) : true;

    const correspondeReconhecimento = filtroReconhecimento ? 
      (filtroReconhecimento === 'sim' ? audiencia.reconhecimento : !audiencia.reconhecimento) : true;

    const correspondeDepoimentoEspecial = filtroDepoimentoEspecial ? 
      (filtroDepoimentoEspecial === 'sim' ? audiencia.depoimentoEspecial : !audiencia.depoimentoEspecial) : true;

    return correspondeAoFiltro && correspondeAData && correspondeReuPreso && 
           correspondeAgendamentoTeams && correspondeReconhecimento && correspondeDepoimentoEspecial;
  });

  // Lógica de paginação
  const totalItens = audienciasFiltradas.length;
  const totalPaginas = Math.ceil(totalItens / itensPorPagina);
  const indiceInicial = (paginaAtual - 1) * itensPorPagina;
  const indiceFinal = indiceInicial + itensPorPagina;
  const audienciasPaginadas = audienciasFiltradas.slice(indiceInicial, indiceFinal);

  const irParaPagina = (pagina: number) => {
    setPaginaAtual(pagina);
  };

  const paginaAnterior = () => {
    if (paginaAtual > 1) {
      setPaginaAtual(paginaAtual - 1);
    }
  };

  const proximaPagina = () => {
    if (paginaAtual < totalPaginas) {
      setPaginaAtual(paginaAtual + 1);
    }
  };

  // Reset da página quando os filtros mudam
  useEffect(() => {
    setPaginaAtual(1);
  }, [filtroProcesso, dataFiltro, filtroCompetencia, filtroReuPreso, filtroAgendamentoTeams, filtroReconhecimento, filtroDepoimentoEspecial]);

  const getStatusBadgeClass = (status: string): string => {
    const statusLower = (status || '').toLowerCase();
    switch (statusLower) {
      case 'designada':
        return 'bg-blue-100 text-blue-800';
      case 'realizada':
        return 'bg-green-100 text-green-800';
      case 'cancelada':
        return 'bg-red-100 text-red-800';
      case 'parcialmente_realizada':
        return 'bg-yellow-100 text-yellow-800';
      case 'redesignada':
        return 'bg-orange-100 text-orange-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Erro!</strong>
        <span className="block sm:inline"> {error}</span>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Audiências</h1>
        <Link 
          to="/audiencias/nova" 
          className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded"
        >
          Nova Audiência
        </Link>
      </div>

      <div className="mb-6 flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <input
            type="text"
            placeholder="Buscar por processo, vara, juiz..."
            className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtroProcesso}
            onChange={(e) => setFiltroProcesso(e.target.value)}
          />
        </div>
        <div className="md:w-64">
          <input
            type="date"
            className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={dataFiltro}
            onChange={(e) => setDataFiltro(e.target.value ? format(new Date(e.target.value), 'dd/MM/yyyy', { locale: ptBR }) : '')}
          />
        </div>
      </div>

      <div className="mb-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Réu Preso</label>
          <select
            className="w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtroReuPreso}
            onChange={(e) => setFiltroReuPreso(e.target.value)}
          >
            <option value="">Todos</option>
            <option value="sim">Sim</option>
            <option value="nao">Não</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Agendamento Teams</label>
          <select
            className="w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtroAgendamentoTeams}
            onChange={(e) => setFiltroAgendamentoTeams(e.target.value)}
          >
            <option value="">Todos</option>
            <option value="sim">Sim</option>
            <option value="nao">Não</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Reconhecimento</label>
          <select
            className="w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtroReconhecimento}
            onChange={(e) => setFiltroReconhecimento(e.target.value)}
          >
            <option value="">Todos</option>
            <option value="sim">Sim</option>
            <option value="nao">Não</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Depoimento Especial</label>
          <select
            className="w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtroDepoimentoEspecial}
            onChange={(e) => setFiltroDepoimentoEspecial(e.target.value)}
          >
            <option value="">Todos</option>
            <option value="sim">Sim</option>
            <option value="nao">Não</option>
          </select>
        </div>
      </div>

      {audienciasFiltradas.length === 0 ? (
        <div className="bg-gray-50 p-6 rounded-lg text-center">
          <p className="text-gray-600">Nenhuma audiência encontrada.</p>
        </div>
      ) : (
        <>
          <div className="overflow-x-auto">
            <table className="min-w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Processo</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Hora</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Vara</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Juiz</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Réu Preso</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Teams</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Reconhec.</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Dep. Esp.</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {audienciasPaginadas.map((audiencia) => (
                <tr key={audiencia.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{audiencia.numeroProcesso}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{formatarData(audiencia.dataAudiencia)}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{formatarHora(audiencia.horarioInicio)}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{audiencia.vara?.nome || 'N/A'}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{audiencia.juiz?.nome || 'N/A'}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${audiencia.reuPreso ? 'bg-red-100 text-red-800' : 'bg-gray-100 text-gray-800'}`}>
                      {audiencia.reuPreso ? 'Sim' : 'Não'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${audiencia.agendamentoTeams ? 'bg-blue-100 text-blue-800' : 'bg-gray-100 text-gray-800'}`}>
                      {audiencia.agendamentoTeams ? 'Sim' : 'Não'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${audiencia.reconhecimento ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'}`}>
                      {audiencia.reconhecimento ? 'Sim' : 'Não'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${audiencia.depoimentoEspecial ? 'bg-purple-100 text-purple-800' : 'bg-gray-100 text-gray-800'}`}>
                      {audiencia.depoimentoEspecial ? 'Sim' : 'Não'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusBadgeClass(audiencia.status || '')}`}>
                      {audiencia.status || 'N/A'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      <Link to={`/audiencias/${audiencia.id}`} className="text-blue-600 hover:text-blue-900">
                        Detalhes
                      </Link>
                      <Link to={`/audiencias/editar/${audiencia.id}`} className="text-indigo-600 hover:text-indigo-900">
                        Editar
                      </Link>
                      <button
                        onClick={() => handleDelete(audiencia.id, audiencia.numeroProcesso)}
                        className="text-red-600 hover:text-red-900"
                      >
                        Excluir
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              </tbody>
            </table>
          </div>

          {/* Paginação */}
          {totalPaginas > 1 && (
            <div className="bg-white px-4 py-3 flex items-center justify-between border-t border-gray-200 sm:px-6 mt-4">
              <div className="flex-1 flex justify-between sm:hidden">
                <button
                  onClick={paginaAnterior}
                  disabled={paginaAtual === 1}
                  className="relative inline-flex items-center px-4 py-2 border border-gray-300 text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Anterior
                </button>
                <button
                  onClick={proximaPagina}
                  disabled={paginaAtual === totalPaginas}
                  className="ml-3 relative inline-flex items-center px-4 py-2 border border-gray-300 text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Próxima
                </button>
              </div>
              <div className="hidden sm:flex-1 sm:flex sm:items-center sm:justify-between">
                <div>
                  <p className="text-sm text-gray-700">
                    Mostrando <span className="font-medium">{indiceInicial + 1}</span> a{' '}
                    <span className="font-medium">{Math.min(indiceFinal, totalItens)}</span> de{' '}
                    <span className="font-medium">{totalItens}</span> resultados
                  </p>
                </div>
                <div>
                  <nav className="relative z-0 inline-flex rounded-md shadow-sm -space-x-px" aria-label="Pagination">
                    <button
                      onClick={paginaAnterior}
                      disabled={paginaAtual === 1}
                      className="relative inline-flex items-center px-2 py-2 rounded-l-md border border-gray-300 bg-white text-sm font-medium text-gray-500 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      <span className="sr-only">Anterior</span>
                      ←
                    </button>
                    {Array.from({ length: totalPaginas }, (_, i) => i + 1).map((numeroPagina) => (
                      <button
                        key={numeroPagina}
                        onClick={() => irParaPagina(numeroPagina)}
                        className={`relative inline-flex items-center px-4 py-2 border text-sm font-medium ${
                          numeroPagina === paginaAtual
                            ? 'z-10 bg-blue-50 border-blue-500 text-blue-600'
                            : 'bg-white border-gray-300 text-gray-500 hover:bg-gray-50'
                        }`}
                      >
                        {numeroPagina}
                      </button>
                    ))}
                    <button
                      onClick={proximaPagina}
                      disabled={paginaAtual === totalPaginas}
                      className="relative inline-flex items-center px-2 py-2 rounded-r-md border border-gray-300 bg-white text-sm font-medium text-gray-500 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      <span className="sr-only">Próxima</span>
                      →
                    </button>
                  </nav>
                </div>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default AudienciasList;
